/**
 * RPG Maker-style equestrian horse sprites for the Racing Pavilion.
 * Original pixel art: 8 realistic coat colors, 4 directions, 3-frame walk cycle.
 * Frame data lives in horse-sprite-frames.js (generated by scripts/generate-horse-sprite-frames.mjs).
 */

import {
  BASE_FRAMES,
  COAT_FRAME_OVERRIDES,
  COAT_PALETTES,
  HORSE_FRAME_H,
  HORSE_FRAME_W,
} from "./horse-sprite-frames.js";

export const HORSE_NATIVE_W = HORSE_FRAME_W;
export const HORSE_NATIVE_H = HORSE_FRAME_H;

export const HORSE_SPRITE_ROSTER = [
  { id: "black", label: "Black" },
  { id: "tan", label: "Tan" },
  { id: "grey", label: "Grey" },
  { id: "chestnut", label: "Chestnut" },
  { id: "light_brown", label: "Light Brown" },
  { id: "dark_brown", label: "Dark Brown" },
  { id: "bay", label: "Bay" },
  { id: "dapple", label: "Dapple Grey" },
];

export const HORSE_SPRITE_COUNT = HORSE_SPRITE_ROSTER.length;

/** Classic table-racing silk colors — one palette per post position. */
export const JOCKEY_SILKS = [
  { name: "Teal", cap: "#58c8e8", shirt: "#40b0d0", sleeves: "#3098b8", pants: "#f0f0f0", trim: "#ffffff" },
  { name: "Rose", cap: "#f098a8", shirt: "#e87898", sleeves: "#d06078", pants: "#f8f0f0", trim: "#ffffff" },
  { name: "Violet", cap: "#a878d8", shirt: "#8860c0", sleeves: "#6848a0", pants: "#f0eef8", trim: "#ffd040" },
  { name: "Gold", cap: "#f0d040", shirt: "#e8b820", sleeves: "#c89810", pants: "#fffef0", trim: "#ffffff" },
  { name: "Crimson", cap: "#c84858", shirt: "#a83040", sleeves: "#881828", pants: "#f8ecec", trim: "#ffffff" },
  { name: "Royal", cap: "#4878e8", shirt: "#3060c8", sleeves: "#2048a0", pants: "#eef0f8", trim: "#ffd040" },
  { name: "Emerald", cap: "#48b878", shirt: "#309860", sleeves: "#208048", pants: "#f0f8f2", trim: "#ffffff" },
  { name: "Orange", cap: "#f0a040", shirt: "#e08828", sleeves: "#c07018", pants: "#fff8f0", trim: "#ffffff" },
];

export function getJockeySilks(horseNumber) {
  return JOCKEY_SILKS[(horseNumber - 1) % JOCKEY_SILKS.length];
}

const SPRITE_BY_ID = Object.fromEntries(HORSE_SPRITE_ROSTER.map((s) => [s.id, s]));

export function getHorseSprite(spriteId) {
  return SPRITE_BY_ID[spriteId] ?? HORSE_SPRITE_ROSTER[0];
}

function shadeColor(hex, amount) {
  const n = parseInt(hex.slice(1), 16);
  let r = (n >> 16) & 0xff;
  let g = (n >> 8) & 0xff;
  let b = n & 0xff;
  if (amount > 0) {
    r = Math.round(r + (255 - r) * amount);
    g = Math.round(g + (255 - g) * amount);
    b = Math.round(b + (255 - b) * amount);
  } else {
    const f = 1 + amount;
    r = Math.max(0, Math.round(r * f));
    g = Math.max(0, Math.round(g * f));
    b = Math.max(0, Math.round(b * f));
  }
  return `#${((r << 16) | (g << 8) | b).toString(16).padStart(6, "0")}`;
}

function px(ctx, x, y, w, h, color, scale) {
  ctx.fillStyle = color;
  ctx.fillRect(x * scale, y * scale, w * scale, h * scale);
}

function resolveDirection(direction, animation) {
  if (direction) return direction;
  if (animation === "trot" || animation === "walk") return "right";
  return "front";
}

function resolveAnimation(animation) {
  if (animation === "idle" || animation === "trot") return "walk";
  return animation;
}

function getFrameRows(spriteId, direction, frameIndex) {
  const override = COAT_FRAME_OVERRIDES[spriteId]?.[direction];
  const rows = override ?? BASE_FRAMES[direction];
  return rows[frameIndex % 3];
}

function drawPixelMap(ctx, spriteId, direction, frameIndex, scale, offsetX, offsetY) {
  const palette = COAT_PALETTES[spriteId] ?? COAT_PALETTES.black;
  const rows = getFrameRows(spriteId, direction, frameIndex);
  for (let y = 0; y < rows.length; y++) {
    const row = rows[y];
    for (let x = 0; x < row.length; x++) {
      const key = row[x];
      if (key === ".") continue;
      const color = palette[key];
      if (color) px(ctx, offsetX + x, offsetY + y, 1, 1, color, scale);
    }
  }
}

function drawJockeyOverlay(ctx, direction, scale, offsetX, offsetY, silks) {
  if (direction === "right") {
    const skin = "#f0d0b0";
    px(ctx, offsetX + 14, offsetY + 8, 3, 2, silks.cap, scale);
    px(ctx, offsetX + 15, offsetY + 7, 2, 1, shadeColor(silks.cap, 0.15), scale);
    px(ctx, offsetX + 15, offsetY + 10, 2, 2, skin, scale);
    px(ctx, offsetX + 13, offsetY + 12, 6, 3, silks.shirt, scale);
    px(ctx, offsetX + 12, offsetY + 13, 1, 2, silks.sleeves, scale);
    px(ctx, offsetX + 19, offsetY + 13, 1, 2, silks.sleeves, scale);
    px(ctx, offsetX + 14, offsetY + 12, 4, 1, silks.trim, scale);
    px(ctx, offsetX + 14, offsetY + 15, 2, 2, silks.pants, scale);
    px(ctx, offsetX + 16, offsetY + 15, 2, 2, silks.pants, scale);
    px(ctx, offsetX + 12, offsetY + 14, 8, 3, silks.shirt, scale);
    px(ctx, offsetX + 13, offsetY + 13, 6, 1, shadeColor(silks.shirt, -0.2), scale);
    px(ctx, offsetX + 14, offsetY + 15, 4, 1, silks.trim, scale);
  } else if (direction === "front") {
    const skin = "#f0d0b0";
    px(ctx, offsetX + 14, offsetY + 9, 4, 2, silks.cap, scale);
    px(ctx, offsetX + 15, offsetY + 11, 2, 2, skin, scale);
    px(ctx, offsetX + 13, offsetY + 13, 6, 3, silks.shirt, scale);
    px(ctx, offsetX + 14, offsetY + 13, 4, 1, silks.trim, scale);
    px(ctx, offsetX + 14, offsetY + 16, 2, 2, silks.pants, scale);
    px(ctx, offsetX + 16, offsetY + 16, 2, 2, silks.pants, scale);
  }
}

/**
 * Draw an equestrian pixel horse from the frame atlas.
 * @param {'front'|'right'|'left'|'back'} direction
 * @param {'walk'|'idle'|'trot'} animation — idle/trot alias to walk
 */
export function drawHorseSprite(ctx, spriteId, {
  scale = 2,
  frame = 0,
  animation = "walk",
  direction = null,
  offsetX = 0,
  offsetY = 0,
  clear = null,
  jockeySilks = null,
} = {}) {
  const anim = resolveAnimation(animation);
  const dir = resolveDirection(direction, animation);
  const frameIndex = frame % 3;

  const shouldClear = clear ?? (offsetX === 0 && offsetY === 0);
  if (shouldClear && ctx.canvas) {
    ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);
  }

  px(ctx, offsetX + 8, offsetY + 28, 16, 1, "rgba(0,0,0,0.18)", scale);
  drawPixelMap(ctx, spriteId, dir, frameIndex, scale, offsetX, offsetY);
  if (jockeySilks) drawJockeyOverlay(ctx, dir, scale, offsetX, offsetY, jockeySilks);
}

/** Draw horse + jockey composited at canvas pixel coordinates. */
export function drawHorseAndJockeyAt(ctx, spriteId, canvasX, canvasY, {
  scale = 1,
  frame = 0,
  animation = "walk",
  direction = "right",
  horseNumber = 1,
  jockeySilks = null,
} = {}) {
  const silks = jockeySilks ?? getJockeySilks(horseNumber);
  drawHorseSprite(ctx, spriteId, {
    scale,
    frame,
    animation,
    direction,
    offsetX: canvasX / scale,
    offsetY: canvasY / scale,
    clear: false,
    jockeySilks: silks,
  });
}

export function createHorseSpriteCanvas(spriteId, {
  size = 80,
  frame = 0,
  animate = false,
  animation = "walk",
  direction = "front",
  horseNumber = 1,
  withJockey = false,
} = {}) {
  const scale = Math.max(1, Math.floor(size / HORSE_NATIVE_W));
  const canvas = document.createElement("canvas");
  canvas.width = HORSE_NATIVE_W * scale;
  canvas.height = HORSE_NATIVE_H * scale;
  canvas.className = "horse-sprite-canvas";
  const ctx = canvas.getContext("2d");
  ctx.imageSmoothingEnabled = false;
  drawHorseSprite(ctx, spriteId, {
    scale,
    frame,
    animation,
    direction,
    jockeySilks: withJockey ? getJockeySilks(horseNumber) : null,
  });
  if (animate) {
    startHorseCanvasAnimation(canvas, spriteId, { animation, direction, horseNumber, withJockey });
  }
  return canvas;
}

/** Cycle 3-frame walk animation. */
export function startHorseCanvasAnimation(canvas, spriteId, {
  fps = 4,
  animation = "walk",
  direction = "front",
  horseNumber = 1,
  withJockey = false,
} = {}) {
  const scale = canvas.width / HORSE_NATIVE_W;
  const ctx = canvas.getContext("2d");
  ctx.imageSmoothingEnabled = false;
  const silks = withJockey ? getJockeySilks(horseNumber) : null;
  let frame = 0;
  const tick = () => {
    drawHorseSprite(ctx, spriteId, {
      scale,
      frame,
      animation,
      direction,
      jockeySilks: silks,
    });
    frame = (frame + 1) % 3;
  };
  tick();
  const id = setInterval(tick, 1000 / fps);
  canvas.dataset.animateId = String(id);
  return id;
}

export function assignHorseSprites(count, startOffset = 0) {
  const ids = HORSE_SPRITE_ROSTER.map((s) => s.id);
  const assigned = [];
  for (let i = 0; i < count; i++) {
    assigned.push(ids[(startOffset + i) % ids.length]);
  }
  return assigned;
}
